                               <div className="flex items-center gap-2">
                                 <MailIcon className="w-5 h-5 text-slate-500"/>
                                 <h3 className="text-lg font-bold">Contact Requests</h3>
                               </div>
                           </header>
                           <div className="p-4">
                               {contactRequests.length > 0 ? (
