                                    >
                                        Regenerate
                                    </button>
                                </div>
                            </div>

                            {codesVisible ? (
                                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                                    {user.backup_codes?.map((code, index) => (
