  // Handle deep link navigation
  useEffect(() => {
      if (deepLinkInfo) {
          if (['profile', 'appearance', 'tools', 'friends', 'account'].includes(deepLinkInfo)) {
              setActiveSection(deepLinkInfo as SettingsSection);
          }
      }
