    const { timeFormat, setTimeFormat, visibleTimezones, setVisibleTimezones } = useTime();
    const [activeCategory, setActiveCategory] = useState<BackgroundCategory | null>(null);

    const timezoneOptions: { id: Timezone, label: string }[] = [
