            <SettingsCard
                title="Taskbar Position"
                description="Change where the taskbar appears on your screen."
            >
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    {(['bottom', 'top', 'left', 'right'] as TaskbarPosition[]).map(pos => (
