        <div className="relative">
            <input id={id} type={show ? 'text' : 'password'} value={value} onChange={onChange} className="modern-input" autoFocus={autoFocus} />
            <button type="button" onClick={onToggle} className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-500 hover:text-slate-700 dark:hover:text-slate-300" aria-label={show ? 'Hide password' : 'Show password'}>
                {show ? <EyeSlashIcon className="w-5 h-5" /> : <EyeIcon className="w-5 h-5" />}
            </button>
