                                                    <XCircleIcon className="w-4 h-4" />
                                                    {passwordError}
                                                </div>
                                            </div>
                                        )}

                                        <div className="flex justify-center gap-3">
                                            <button 
                                                type="button" 
                                                onClick={() => setPasswordChangeStep(2)} 
