// Helper to render timeline progress
const TimelineHeader = ({ step, title1, title2, title3 }: { step: number; title1: string; title2: string; title3: string }) => {
    const isStep1Completed = step > 1;
    const isStep2Completed = step > 2;
    const isStep3Completed = step > 3; 

    // Helper for node classes
    const getNodeClasses = (stepNum: number) => {
        const isActive = step === stepNum;
        const isCompleted = step > stepNum;

        if (isCompleted) return 'bg-emerald-500 border-emerald-500 text-white';
        if (isActive) return 'bg-emerald-500 border-emerald-500 text-white ring-4 ring-emerald-500/20';
        return 'bg-white dark:bg-slate-800 border-slate-300 dark:border-slate-600 text-slate-400';
    };

    const getTextClasses = (stepNum: number) => {
        const isActiveOrCompleted = step >= stepNum;
        return isActiveOrCompleted ? 'text-emerald-600 dark:text-emerald-400 font-bold' : 'text-slate-400 font-medium';
    };

    return (
        <div className="w-full px-2 mb-10">
            <div className="flex items-center w-full">
                {/* Step 1 */}
                <div className="relative flex flex-col items-center group">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold border-2 transition-all duration-300 z-10 ${getNodeClasses(1)}`}>
                        {isStep1Completed ? <CheckIcon className="w-4 h-4 stroke-[3]" /> : '1'}
                    </div>
                    <div className={`absolute -bottom-6 w-32 text-center text-[10px] uppercase tracking-wider transition-colors duration-300 ${getTextClasses(1)}`}>
                        {title1}
                    </div>
                </div>

                {/* Connector 1-2 */}
                <div className="flex-1 h-1 mx-2 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden relative">
                    <div className={`absolute top-0 left-0 h-full bg-emerald-500 transition-all duration-[1500ms] ease-in-out rounded-full ${step > 1 ? 'w-full' : 'w-0'}`}></div>
                </div>

                {/* Step 2 */}
                <div className="relative flex flex-col items-center group">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold border-2 transition-all duration-300 z-10 ${getNodeClasses(2)}`}>
                        {isStep2Completed ? <CheckIcon className="w-4 h-4 stroke-[3]" /> : '2'}
                    </div>
                    <div className={`absolute -bottom-6 w-32 text-center text-[10px] uppercase tracking-wider transition-colors duration-300 ${getTextClasses(2)}`}>
                        {title2}
                    </div>
                </div>

                {/* Connector 2-3 */}
                <div className="flex-1 h-1 mx-2 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden relative">
                     <div className={`absolute top-0 left-0 h-full bg-emerald-500 transition-all duration-[1500ms] ease-in-out rounded-full ${step > 2 ? 'w-full' : 'w-0'}`}></div>
                </div>

                {/* Step 3 */}
                <div className="relative flex flex-col items-center group">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold border-2 transition-all duration-300 z-10 ${getNodeClasses(3)}`}>
                         {step > 3 ? <CheckIcon className="w-4 h-4 stroke-[3]" /> : '3'}
                    </div>
                    <div className={`absolute -bottom-6 w-32 text-center text-[10px] uppercase tracking-wider transition-colors duration-300 ${getTextClasses(3)}`}>
                        {title3}
                    </div>
                </div>
            </div>
        </div>
    );
};

