interface SettingsPageProps {
  user: User;
  allUsers: User[];
  onLogout: () => void;
  onProfileUpdate: (email: string, updatedData: Partial<User>, silent?: boolean) => Promise<void>;
  taskbarPosition: TaskbarPosition;
  setTaskbarPosition: (pos: TaskbarPosition) => void;
  desktopIconSize: DesktopIconSize;
  setDesktopIconSize: (size: DesktopIconSize) => void;
  pinnedAppIds: string[];
  setPinnedAppIds: (ids: string[]) => void;
  allApps: AppDefinition[];
  onSendFriendRequest: (fromUser: User, toUserEmail: string) => Promise<void>;
  onAcceptFriendRequest: (requestor: { email: string; name: string }) => Promise<void>;
  onRejectFriendRequest: (requestor: { email: string; name: string }) => Promise<void>;
  onRemoveFriend: (friendToRemove: { email: string; name: string }) => Promise<void>;
  onDeleteAccount: () => Promise<string | void>;
  onVerifyPassword: (password: string) => Promise<boolean>;
  onEmailChange: (newEmail: string) => Promise<string | void>;
  onClose?: () => void;
}

const SettingsPage: React.FC<SettingsPageProps> = ({
    user, allUsers, onLogout, onProfileUpdate, 
    taskbarPosition, setTaskbarPosition, desktopIconSize, setDesktopIconSize, 
    pinnedAppIds, setPinnedAppIds, allApps,
    onSendFriendRequest, onAcceptFriendRequest, onRejectFriendRequest, onRemoveFriend,
    onDeleteAccount, onVerifyPassword, onEmailChange
}) => {
    const [activeTab, setActiveTab] = useState<'account' | 'appearance' | 'display' | 'security' | 'friends'>('account');
    const { themeStyle, setThemeStyle, themeMode, setThemeMode, backgroundCategories, selectedBackground, setSelectedBackground, selectedFont, setSelectedFont } = useTheme();
    const { addNotification } = useNotificationState();
    const [isSaving, setIsSaving] = useState(false);
    const [isUploading, setIsUploading] = useState(false);

    // Account State
    const [displayName, setDisplayName] = useState(user.name);
    const [email, setEmail] = useState(user.email);
    const [bio, setBio] = useState(user.bio || '');
    const [isPrivate, setIsPrivate] = useState(user.is_profile_private || false);

    // Security State
    const [currentPassword, setCurrentPassword] = useState('');
    const [showCurrentPassword, setShowCurrentPassword] = useState(false);
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);

    // Friends State
    const [friendSearch, setFriendSearch] = useState('');

    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAvatarClick = () => {
        fileInputRef.current?.click();
    };

    const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setIsUploading(true);
        try {
            const url = await uploadToCloudinary(file);
            await onProfileUpdate(user.email, { avatar: url });
            addNotification({ title: 'Avatar Updated', message: 'Your profile picture has been updated.', type: 'success' });
        } catch (error) {
            addNotification({ title: 'Upload Failed', message: 'Could not upload image.', type: 'error' });
        } finally {
            setIsUploading(false);
        }
    };

    const handleAccountSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);

        try {
            const updates: Partial<User> = { name: displayName, bio, is_profile_private: isPrivate };
            await onProfileUpdate(user.email, updates);

            if (email !== user.email) {
                const result = await onEmailChange(email);
                if (result) {
                    addNotification({ title: 'Error', message: result, type: 'error' });
                } else {
                    addNotification({ title: 'Check Your Email', message: 'A verification link has been sent to your new email.', type: 'info' });
                }
            } else {
                addNotification({ title: 'Profile Updated', message: 'Your account settings have been saved.', type: 'success' });
            }
        } catch (error) {
            addNotification({ title: 'Error', message: 'Failed to update profile.', type: 'error' });
        } finally {
            setIsSaving(false);
        }
    };

    const handleFriendRequest = async (targetUserEmail: string) => {
        await onSendFriendRequest(user, targetUserEmail);
    };

    const handleDeleteAccountConfirm = async () => {
        const error = await onDeleteAccount();
        if (error) {
            addNotification({ title: 'Error', message: error, type: 'error' });
        } else {
            // User logged out automatically
        }
        setIsDeleteModalOpen(false);
    };

    const filteredUsers = useMemo(() => {
        if (!friendSearch) return [];
        const lowerSearch = friendSearch.toLowerCase();
        return allUsers.filter(u => 
            u.email !== user.email && 
            u.role !== 'admin' &&
            (u.name.toLowerCase().includes(lowerSearch) || u.email.toLowerCase().includes(lowerSearch))
        );
    }, [allUsers, friendSearch, user.email]);

    return (
        <div className="flex h-full w-full bg-slate-50 dark:bg-slate-900 overflow-hidden">
            <ConfirmationModal
                isOpen={isDeleteModalOpen}
                onClose={() => setIsDeleteModalOpen(false)}
                onConfirm={handleDeleteAccountConfirm}
                title="Delete Account"
                confirmText="Yes, Delete My Account"
                confirmButtonClass="bg-red-600 hover:bg-red-700"
            >
                <p>Are you absolutely sure? This action cannot be undone. This will permanently delete your account and remove your data from our servers.</p>
            </ConfirmationModal>

            {/* Sidebar */}
            <aside className="w-64 bg-slate-100 dark:bg-slate-800/50 border-r border-slate-200 dark:border-slate-700 flex-shrink-0 flex flex-col">
                <div className="p-6">
                    <h2 className="text-xl font-bold text-slate-800 dark:text-white">Settings</h2>
                </div>
                <nav className="flex-1 px-4 space-y-1">
                    <button onClick={() => setActiveTab('account')} className={`w-full flex items-center gap-3 px-3 py-2 text-sm font-medium rounded-md transition-colors ${activeTab === 'account' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'}`}>
                        <UserIcon className="w-5 h-5"/> Account
                    </button>
                    <button onClick={() => setActiveTab('appearance')} className={`w-full flex items-center gap-3 px-3 py-2 text-sm font-medium rounded-md transition-colors ${activeTab === 'appearance' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'}`}>
                        <PaletteIcon className="w-5 h-5"/> Appearance
                    </button>
                    <button onClick={() => setActiveTab('display')} className={`w-full flex items-center gap-3 px-3 py-2 text-sm font-medium rounded-md transition-colors ${activeTab === 'display' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'}`}>
                        <DisplayIcon className="w-5 h-5"/> Desktop
                    </button>
                    <button onClick={() => setActiveTab('friends')} className={`w-full flex items-center gap-3 px-3 py-2 text-sm font-medium rounded-md transition-colors ${activeTab === 'friends' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'}`}>
                        <UsersIcon className="w-5 h-5"/> Friends
                    </button>
                    <button onClick={() => setActiveTab('security')} className={`w-full flex items-center gap-3 px-3 py-2 text-sm font-medium rounded-md transition-colors ${activeTab === 'security' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'}`}>
                        <ShieldIcon className="w-5 h-5"/> Security
                    </button>
                </nav>
                <div className="p-4 border-t border-slate-200 dark:border-slate-700">
                    <div className="flex items-center gap-3 px-3 py-2">
                        <img src={getCloudinaryUrl(user.avatar, { width: 40, height: 40, radius: 'max' })} alt={user.name} className="w-10 h-10 rounded-full" />
                        <div className="overflow-hidden">
                            <p className="text-sm font-medium text-slate-900 dark:text-white truncate">{user.name}</p>
                            <p className="text-xs text-slate-500 dark:text-slate-400 truncate">{user.email}</p>
                        </div>
                    </div>
                </div>
            </aside>

            {/* Main Content */}
            <main className="flex-1 overflow-y-auto p-8">
                {activeTab === 'account' && (
                    <div className="max-w-2xl mx-auto space-y-8 animate-fade-in">
                        <h3 className="text-2xl font-bold text-slate-800 dark:text-white">Account Settings</h3>

                        <div className="flex items-center gap-6">
                            <div className="relative group cursor-pointer" onClick={handleAvatarClick}>
                                <img 
                                    src={getCloudinaryUrl(user.avatar, { width: 96, height: 96, radius: 'max' })} 
                                    alt="Profile" 
                                    className="w-24 h-24 rounded-full object-cover border-4 border-white dark:border-slate-700 shadow-md group-hover:opacity-75 transition-opacity" 
                                />
                                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                    <span className="bg-black/50 text-white text-xs px-2 py-1 rounded">Change</span>
                                </div>
                                {isUploading && <div className="absolute inset-0 flex items-center justify-center bg-white/50 dark:bg-black/50 rounded-full"><SpinnerIcon className="w-6 h-6 animate-spin text-indigo-600"/></div>}
                            </div>
                            <div>
                                <h4 className="text-lg font-medium">{user.name}</h4>
                                <p className="text-sm text-slate-500">Click image to upload new photo</p>
                                <input type="file" ref={fileInputRef} onChange={handleAvatarChange} className="hidden" accept="image/*" />
                            </div>
                        </div>

                        <form onSubmit={handleAccountSave} className="space-y-6">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Display Name</label>
                                <input type="text" value={displayName} onChange={e => setDisplayName(e.target.value)} className="modern-input" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Email Address</label>
                                <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="modern-input" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Bio</label>
                                <textarea value={bio} onChange={e => setBio(e.target.value)} className="modern-textarea" rows={3} placeholder="Tell us about yourself..." />
                            </div>
                            <div className="flex items-center gap-2">
                                <input type="checkbox" id="isPrivate" checked={isPrivate} onChange={e => setIsPrivate(e.target.checked)} className="rounded border-slate-300 text-indigo-600 focus:ring-indigo-500" />
                                <label htmlFor="isPrivate" className="text-sm text-slate-700 dark:text-slate-300">Make profile private (only friends can see details)</label>
                            </div>
                            <div className="pt-4">
                                <button type="submit" disabled={isSaving} className="btn w-full sm:w-auto">
                                    {isSaving ? <SpinnerIcon className="w-5 h-5 animate-spin mx-auto"/> : 'Save Changes'}
                                </button>
                            </div>
                        </form>
                    </div>
                )}

                {activeTab === 'appearance' && (
                    <div className="max-w-2xl mx-auto space-y-8 animate-fade-in">
                        <h3 className="text-2xl font-bold text-slate-800 dark:text-white">Appearance</h3>

                        <div className="space-y-4">
                            <label className="text-sm font-bold uppercase text-slate-500">Theme Mode</label>
                            <div className="grid grid-cols-2 gap-4">
                                <button onClick={() => setThemeMode('light')} className={`p-4 rounded-xl border-2 flex items-center justify-center gap-2 transition-all ${themeMode === 'light' ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-300' : 'border-slate-200 dark:border-slate-700 hover:border-slate-300'}`}>
                                    <span className="w-4 h-4 rounded-full bg-white border border-slate-300"></span> Light
                                </button>
                                <button onClick={() => setThemeMode('dark')} className={`p-4 rounded-xl border-2 flex items-center justify-center gap-2 transition-all ${themeMode === 'dark' ? 'border-indigo-500 bg-slate-800 text-white' : 'border-slate-200 dark:border-slate-700 hover:border-slate-300'}`}>
                                    <span className="w-4 h-4 rounded-full bg-slate-900 border border-slate-700"></span> Dark
                                </button>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <label className="text-sm font-bold uppercase text-slate-500">Window Style</label>
                            <div className="grid grid-cols-2 gap-4">
                                <button onClick={() => setThemeStyle('windows')} className={`p-4 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${themeStyle === 'windows' ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20' : 'border-slate-200 dark:border-slate-700'}`}>
                                    <div className="w-full h-8 bg-slate-200 dark:bg-slate-700 rounded-t flex items-center px-2 gap-1">
                                        <div className="w-full h-full flex justify-end items-center gap-1"><div className="w-3 h-3 bg-slate-400 rounded-sm"></div></div>
                                    </div>
                                    <span className="text-sm font-medium">Windows</span>
                                </button>
                                <button onClick={() => setThemeStyle('mac')} className={`p-4 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${themeStyle === 'mac' ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20' : 'border-slate-200 dark:border-slate-700'}`}>
                                    <div className="w-full h-8 bg-slate-200 dark:bg-slate-700 rounded-t flex items-center px-2 gap-1">
                                        <div className="w-2.5 h-2.5 rounded-full bg-red-400"></div>
                                        <div className="w-2.5 h-2.5 rounded-full bg-yellow-400"></div>
                                        <div className="w-2.5 h-2.5 rounded-full bg-green-400"></div>
                                    </div>
                                    <span className="text-sm font-medium">macOS</span>
                                </button>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <label className="text-sm font-bold uppercase text-slate-500">Wallpaper</label>
                            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                                {backgroundCategories.flatMap(cat => cat.images).slice(0, 8).map((bg, idx) => (
                                    <button 
                                        key={idx} 
                                        onClick={() => setSelectedBackground(bg)}
                                        className={`relative aspect-video rounded-lg overflow-hidden border-2 transition-all ${selectedBackground === bg ? 'border-indigo-500 ring-2 ring-indigo-500 ring-offset-2 dark:ring-offset-slate-900' : 'border-transparent hover:opacity-80'}`}
                                    >
                                        <img src={getCloudinaryUrl(bg, { width: 200, height: 120 })} alt="Wallpaper" className="w-full h-full object-cover" />
