                            <span aria-hidden="true" className={`inline-block h-5 w-5 rounded-full bg-white shadow transform ring-0 transition ease-in-out duration-200 ${user.is_2fa_enabled ? 'translate-x-5' : 'translate-x-0'}`}/>
